// Move to a dispatcher for blocking work, then come back to Main for UI
viewModelScope.launch {
  val users = withContext(Dispatchers.IO) { api.fetchUsers() }   // network on IO
  ui.value = users                                                 // back on Main automatically
}

// Room and Retrofit ALREADY handle this — they run their internal work
// on IO by themselves. So you rarely need withContext() explicitly.

// Without structured concurrency (bad old thread days):
// You launch a background task. You forget to cancel it. It runs after
// the Activity dies. It touches views. It NPE's. You lose sleep.

// With structured concurrency:
viewModelScope.launch {          // parent scope
  val a = async { api.fetchA() } // child 1
  val b = async { api.fetchB() } // child 2
  ui.value = merge(a.await(), b.await())
}
// If ANY child throws → the parent is cancelled → all siblings cancel.
// If the ViewModel is destroyed → viewModelScope cancels → both async's cancel.
// You cannot LEAK a coroutine. The tree of coroutines is guaranteed to unwind together.

// Cold flow — nothing runs until you collect
fun tick(): Flow<Int> = flow {
  var i = 0
  while (true) { emit(i++); delay(1000) }
}

// Operators — transform / combine / filter
fun search(query: Flow<String>, api: Api): Flow<List<Result>> =
  query
    .debounce(300)                       // wait for typing to pause
    .distinctUntilChanged()              // skip duplicates
    .filter { it.length >= 2 }
    .flatMapLatest { api.search(it) }   // cancel previous search when new one arrives
    .flowOn(Dispatchers.IO)              // upstream runs on IO; collectors get results on collector's dispatcher

// Collect in a Fragment safely
viewLifecycleOwner.lifecycleScope.launch {
  repeatOnLifecycle(Lifecycle.State.STARTED) {
    search(queryFlow, api).collect { results -> adapter.submit(results) }
  }
}

// StateFlow — one always-present value; perfect for UI state
private val _ui = MutableStateFlow(HomeUi(loading = true))
val ui: StateFlow<HomeUi> = _ui.asStateFlow()

_ui.value = _ui.value.copy(users = list, loading = false)

// SharedFlow — broadcast; perfect for one-shot events (nav, snackbar)
private val _events = MutableSharedFlow<Event>(extraBufferCapacity = 1)
val events: SharedFlow<Event> = _events.asSharedFlow()

fun onSaveClicked() {
  viewModelScope.launch { _events.emit(Event.NavigateBack) }
}

// Rule of thumb:
//   StateFlow = state that's ALWAYS current (form fields, list, loading flag)
//   SharedFlow = fire-once events (navigate, show toast) — no replay by default

// File: SearchViewModel.kt
class SearchViewModel(private val api: Api) : ViewModel() {

  private val query = MutableStateFlow("")

  // Reactive: as the user types, results update
  val results: StateFlow<List<Result>> = query
    .debounce(300)
    .distinctUntilChanged()
    .filter { it.length >= 2 }
    .flatMapLatest { q ->
      // Cold flow: emits Loading, then Data (or Error)
      flow {
        try { emit(api.search(q)) }
        catch (e: Exception) { emit(emptyList()) }
      }
    }
    .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5_000), emptyList())

  fun onQuery(q: String) { query.value = q }
}

// Fragment side
viewLifecycleOwner.lifecycleScope.launch {
  repeatOnLifecycle(Lifecycle.State.STARTED) {
    launch { vm.results.collect { adapter.submitList(it) } }
  }
}

// What this achieves:
// - Debounces typing (300ms of quiet before firing a request)
// - Skips duplicates
// - Cancels the previous search when the user types a new letter (flatMapLatest)
// - Multiplexes to any Fragment that observes
// - Cancels EVERYTHING if the ViewModel is destroyed
// All in ~10 lines. Try writing this with callbacks and threads.

